  1→import React, { useEffect, useMemo } from 'react';
  2→import { useNavigate } from 'react-router-dom';
  3→import { useInView } from 'react-intersection-observer';
  4→import { useAuth } from '../../../Context/useAuth';
  5→import { useMyStories } from '../hooks/useStoryData';
  6→import { useDeleteStory } from '../hooks/useStoryMutations';
  7→import { motion, AnimatePresence } from 'framer-motion';
  8→import { BeatLoader } from 'react-spinners';
  9→import './StoryDashboard.css';
 10→
 11→const STATUS_LABELS = {
 12→    ongoing: 'Ongoing',
 13→    completed: 'Completed',
 14→    hiatus: 'Hiatus',
 15→};
 16→
 17→const StoryDashboard = () => {
 18→    const { session } = useAuth();
 19→    const token = session?.access_token;
 20→    const navigate = useNavigate();
 21→
 22→    const { data, fetchNextPage, hasNextPage, isFetchingNextPage, isLoading } = useMyStories(token);
 23→    const stories = useMemo(() => data?.pages?.flatMap(page => page.data) || [], [data]);
 24→    const deleteMutation = useDeleteStory(token);
 25→
 26→    const { ref: sentinelRef, inView } = useInView();
 27→    useEffect(() => {
 28→        if (inView && hasNextPage && !isFetchingNextPage) {
 29→            fetchNextPage();
 30→        }
 31→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);
 32→
 33→    const handleDelete = (e, storyId, title) => {
 34→        e.stopPropagation();
 35→        if (window.confirm(`Delete "${title}"? This cannot be undone.`)) {
 36→            deleteMutation.mutate(storyId);
 37→        }
 38→    };
 39→
 40→    const getTotalWords = (chapters) => {
 41→        if (!chapters) return 0;
 42→        return chapters.reduce((sum, ch) => sum + (ch.word_count || 0), 0);
 43→    };
 44→
 45→    const getPublishedCount = (chapters) => {
 46→        if (!chapters) return 0;
 47→        return chapters.filter(ch => ch.status === 'published').length;
 48→    };
 49→
 50→    if (isLoading) {
 51→        return (
 52→            <div className="story-dashboard">
 53→                <div className="story-dashboard-loading">
 54→                    <BeatLoader size={10} color="var(--text-muted)" />
 55→                </div>
 56→            </div>
 57→        );
 58→    }
 59→
 60→    return (
 61→        <div className="story-dashboard">
 62→            <div className="story-dashboard-header">
 63→                <button className="story-dashboard-back" onClick={() => navigate(-1)}>
 64→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
 65→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 66→                    </svg>
 67→                </button>
 68→                <h2 className="story-dashboard-title">My Stories</h2>
 69→                <button
 70→                    className="story-dashboard-new-btn"
 71→                    onClick={() => navigate('/home/stories/new')}
 72→                >
 73→                    + New Story
 74→                </button>
 75→            </div>
 76→
 77→            {(!isLoading && stories.length === 0) ? (
 78→                <div className="story-dashboard-empty">
 79→                    <p>You haven't written any stories yet.</p>
 80→                    <button
 81→                        className="story-dashboard-new-btn"
 82→                        onClick={() => navigate('/home/stories/new')}
 83→                    >
 84→                        Write Your First Story
 85→                    </button>
 86→                </div>
 87→            ) : (
 88→                <div className="story-dashboard-list">
 89→                    <AnimatePresence>
 90→                        {stories.map((story) => (
 91→                            <motion.div
 92→                                key={story.id}
 93→                                className="story-dashboard-card"
 94→                                initial={{ opacity: 0, y: 10 }}
 95→                                animate={{ opacity: 1, y: 0 }}
 96→                                exit={{ opacity: 0, y: -10 }}
 97→                                onClick={() => navigate(`/home/stories/${story.id}/manage`)}
 98→                            >
 99→                                <div className="story-dashboard-card-cover">
100→                                    {story.cover_url ? (
101→                                        <img src={story.cover_url} alt={story.title} loading="lazy" />
102→                                    ) : (
103→                                        <div className="story-dashboard-card-cover-placeholder">
104→                                            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="var(--text-muted)">
105→                                                <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
106→                                            </svg>
107→                                        </div>
108→                                    )}
109→                                </div>
110→                                <div className="story-dashboard-card-info">
111→                                    <h3 className="story-dashboard-card-title">{story.title}</h3>
112→                                    <div className="story-dashboard-card-meta">
113→                                        <span className={`story-status-badge story-status-${story.status}`}>
114→                                            {STATUS_LABELS[story.status] || story.status}
115→                                        </span>
116→                                        <span className="story-meta-dot">&middot;</span>
117→                                        <span>{getPublishedCount(story.chapters)}/{(story.chapters || []).length} chapters</span>
118→                                        <span className="story-meta-dot">&middot;</span>
119→                                        <span>{getTotalWords(story.chapters).toLocaleString()} words</span>
120→                                    </div>
121→                                    <div className="story-dashboard-card-stats">
122→                                        <span>{story.read_count || 0} reads</span>
123→                                        <span>{story.vote_count || 0} votes</span>
124→                                    </div>
125→                                </div>
126→                                <div className="story-dashboard-card-actions">
127→                                    <button
128→                                        className="story-action-btn"
129→                                        onClick={(e) => {
130→                                            e.stopPropagation();
131→                                            navigate(`/home/stories/${story.id}/edit`);
132→                                        }}
133→                                        title="Edit story details"
134→                                    >
135→                                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="var(--text-secondary)">
136→                                            <path d="M3 17.25V21h3.75L17.81 9.94l-3.75-3.75L3 17.25zM20.71 7.04c.39-.39.39-1.02 0-1.41l-2.34-2.34c-.39-.39-1.02-.39-1.41 0l-1.83 1.83 3.75 3.75 1.83-1.83z"/>
137→                                        </svg>
138→                                    </button>
139→                                    <button
140→                                        className="story-action-btn story-action-btn-danger"
141→                                        onClick={(e) => handleDelete(e, story.id, story.title)}
142→                                        title="Delete story"
